export declare const PUBLIC_CARD_STYLES = "\n  :root {\n    --link-blue: #0a6bff;\n    --accent: #0a6bff;\n    --text: #ffffff;\n    --text-muted: rgba(255, 255, 255, 0.78);\n    --btn-height: 58px;\n    --radius-lg: 16px;\n    --radius-xl: 20px;\n    --page-bg: #121212;\n    --sheet-bg: transparent;\n    --btn-primary-bg: var(--accent);\n    --btn-primary-text: #ffffff;\n    --btn-muted-bg: rgba(255, 255, 255, 0.12);\n    --btn-muted-text: #ffffff;\n    --btn-border: rgba(10, 107, 255, 0.55);\n    --social-bg: rgba(255, 255, 255, 0.14);\n    --social-border: rgba(10, 107, 255, 0.45);\n  }\n\n  * { box-sizing: border-box; margin: 0; padding: 0; }\n\n  body {\n    font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n    background: #0c0d10;\n    color: var(--text);\n    min-height: 100vh;\n  }\n\n  body:has(.layout-bubble) {\n    background: #ffffff;\n  }\n\n  .page {\n    min-height: 100vh;\n    display: flex;\n    justify-content: center;\n    background: var(--page-bg);\n  }\n\n  .layout-arc.page {\n    background: var(--accent);\n  }\n\n  .shell {\n    width: 100%;\n    max-width: 430px;\n    min-height: 100vh;\n    position: relative;\n    overflow: hidden;\n  }\n\n  .content {\n    padding: 24px 20px 40px;\n  }\n\n  .layout-arc .content,\n  .layout-bubble .content {\n    padding-left: 0;\n    padding-right: 0;\n  }\n\n  .avatar-wrap {\n    display: flex;\n    justify-content: center;\n    margin-bottom: 20px;\n  }\n\n  .layout-nuit .avatar-wrap {\n    justify-content: flex-start;\n  }\n\n  .avatar {\n    width: 136px;\n    height: 136px;\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 36px;\n    font-weight: 700;\n    letter-spacing: -0.5px;\n    overflow: hidden;\n    flex-shrink: 0;\n  }\n\n  .avatar img {\n    width: 100%;\n    height: 100%;\n    object-fit: cover;\n  }\n\n  .layout-nuit .avatar {\n    width: 88px;\n    height: 88px;\n    border-radius: 18px;\n    font-size: 28px;\n    background: #ffffff;\n    color: var(--accent);\n  }\n\n  .layout-or .avatar {\n    background: var(--accent);\n    color: #1a1a1a;\n    box-shadow: 0 0 28px rgba(212, 168, 67, 0.4);\n  }\n\n  .avatar-light-ring {\n    background: #ffffff;\n    color: var(--accent);\n    box-shadow: 0 0 28px rgba(255, 255, 255, 0.35);\n  }\n\n  .avatar-accent-fill {\n    background: var(--accent);\n    color: #ffffff;\n    box-shadow: 0 0 24px color-mix(in srgb, var(--accent) 35%, transparent);\n  }\n\n  .name {\n    font-size: 28px;\n    font-weight: 700;\n    letter-spacing: -0.3px;\n    line-height: 1.15;\n    text-align: center;\n    color: var(--text);\n  }\n\n  .layout-nuit .name,\n  .layout-nuit .subtitle {\n    text-align: left;\n  }\n\n  .subtitle {\n    margin-top: 8px;\n    font-size: 15px;\n    line-height: 1.35;\n    text-align: center;\n    color: var(--text-muted);\n  }\n\n  .actions {\n    margin-top: 24px;\n    display: grid;\n    gap: 8px;\n  }\n\n  .btn {\n    height: 58px;\n    border-radius: 16px;\n    border: 1px solid transparent;\n    display: flex;\n    align-items: center;\n    justify-content: flex-start;\n    gap: 12px;\n    padding: 0 16px;\n    font-size: 15px;\n    font-weight: 600;\n    line-height: 1.2;\n    text-decoration: none;\n    cursor: pointer;\n    width: 100%;\n    background: transparent;\n    color: inherit;\n    font-family: inherit;\n    appearance: none;\n    -webkit-appearance: none;\n  }\n\n  .btn-icon {\n    width: 20px;\n    height: 20px;\n    flex-shrink: 0;\n    display: inline-flex;\n    align-items: center;\n    justify-content: center;\n  }\n\n  .btn-icon svg {\n    display: block;\n    width: 20px;\n    height: 20px;\n  }\n\n  .btn-label {\n    flex: 1;\n    min-width: 0;\n    overflow: hidden;\n    text-overflow: ellipsis;\n    white-space: nowrap;\n    text-align: left;\n  }\n\n  .btn.is-disabled,\n  .btn:disabled {\n    opacity: 0.55;\n    cursor: not-allowed;\n  }\n\n  .btn-primary-accent {\n    background: var(--accent);\n    color: #ffffff;\n  }\n\n  .btn-soft {\n    background: #f2f2f7;\n    color: #0c0d10;\n    border-color: transparent;\n  }\n\n  .btn-white-accent {\n    background: #ffffff;\n    color: var(--accent);\n  }\n\n  .btn-surface-outline {\n    background: #ffffff;\n    color: var(--accent);\n    border-color: color-mix(in srgb, var(--accent) 35%, transparent);\n  }\n\n  .btn-white-outline {\n    background: transparent;\n    color: #ffffff;\n    border-color: rgba(255, 255, 255, 0.55);\n  }\n\n  .btn-glass {\n    background: rgba(255, 255, 255, 0.14);\n    color: #ffffff;\n    border-color: rgba(255, 255, 255, 0.28);\n  }\n\n  .btn-glass-subtle {\n    background: rgba(255, 255, 255, 0.08);\n    color: #ffffff;\n    border-color: rgba(255, 255, 255, 0.18);\n  }\n\n  .btn-white-dark {\n    background: #ffffff;\n    color: #0c0d10;\n  }\n\n  .btn-accent-dark {\n    background: var(--accent);\n    color: #1a1a1a;\n  }\n\n  .btn-outline-white-soft {\n    background: transparent;\n    color: #ffffff;\n    border-color: rgba(255, 255, 255, 0.35);\n  }\n\n  .section-label {\n    margin-top: 24px;\n    margin-bottom: 14px;\n    font-size: 12px;\n    font-weight: 600;\n    letter-spacing: 1.1px;\n    color: var(--text-muted);\n    text-align: left;\n  }\n\n  .socials {\n    display: flex;\n    flex-wrap: wrap;\n    gap: 12px;\n  }\n\n  .social-link {\n    width: 52px;\n    height: 52px;\n    border-radius: 12px;\n    display: inline-flex;\n    align-items: center;\n    justify-content: center;\n    text-decoration: none;\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: 0.2px;\n    padding: 8px;\n    box-sizing: border-box;\n  }\n\n  .social-soft {\n    background: #f2f2f7;\n    color: #0c0d10;\n    border: 1px solid #e5e5ea;\n  }\n\n  .social-accent {\n    background: color-mix(in srgb, var(--accent) 6%, #ffffff);\n    color: var(--accent);\n    border: 1px solid color-mix(in srgb, var(--accent) 20%, transparent);\n  }\n\n  .social-glass {\n    background: rgba(255, 255, 255, 0.14);\n    color: #ffffff;\n    border: 1px solid rgba(255, 255, 255, 0.18);\n  }\n\n  .layout-corail-gradient .social-glass {\n    border-color: rgba(255, 255, 255, 0.28);\n  }\n\n  .brand {\n    margin-top: 28px;\n    display: inline-flex;\n    align-items: center;\n    gap: 8px;\n    color: var(--text-muted);\n    font-size: 14px;\n    font-weight: 600;\n  }\n\n  .brand img {\n    width: 22px;\n    height: 22px;\n    border-radius: 6px;\n  }\n\n  .layout-bubble {\n    background: #ffffff;\n  }\n\n  .layout-bubble .bubble-stage {\n    position: relative;\n    background: #ffffff;\n  }\n\n  .layout-bubble .bubble-header {\n    position: relative;\n    width: 100%;\n    height: 88px;\n    line-height: 0;\n  }\n\n  .layout-bubble .bubble-header-shape {\n    display: block;\n    width: 100%;\n    height: 88px;\n  }\n\n  .layout-bubble .bubble-avatar-slot {\n    position: absolute;\n    top: 32px;\n    left: 50%;\n    transform: translateX(-50%);\n    z-index: 2;\n  }\n\n  .layout-bubble .bubble-avatar-slot .avatar,\n  .layout-bubble .avatar.bubble-avatar {\n    width: 112px;\n    height: 112px;\n    background: #ffffff;\n    box-shadow: 0 8px 28px rgba(12, 13, 16, 0.12);\n  }\n\n  .layout-bubble .bubble-body {\n    margin-top: 80px;\n    background: #ffffff;\n    padding: 0 20px 40px;\n  }\n\n  .layout-arc .shell {\n    min-height: 100vh;\n    overflow: visible;\n  }\n\n  .layout-arc .arc-stage {\n    position: relative;\n    min-height: 100vh;\n    background: var(--accent);\n  }\n\n  .layout-arc .arc-sheet {\n    position: absolute;\n    top: 132px;\n    left: 24px;\n    right: 24px;\n    bottom: 0;\n    background: #ffffff;\n    border-radius: 50px 50px 0 0;\n    padding: 74px 16px 40px;\n  }\n\n  .layout-arc .arc-avatar-wrap {\n    position: absolute;\n    top: 62px;\n    left: 50%;\n    transform: translateX(-50%);\n    z-index: 2;\n  }\n\n  .layout-arc .arc-avatar-ring {\n    width: 140px;\n    height: 140px;\n    border-radius: 50%;\n    background: #ffffff;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    box-shadow: 0 8px 28px rgba(12, 13, 16, 0.08);\n  }\n\n  .layout-arc .arc-avatar-core {\n    width: 124px;\n    height: 124px;\n    border-radius: 50%;\n    background: var(--accent);\n    color: #ffffff;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 36px;\n    font-weight: 700;\n    letter-spacing: -0.5px;\n    overflow: hidden;\n  }\n\n  .layout-arc .arc-avatar-core img {\n    width: 100%;\n    height: 100%;\n    object-fit: cover;\n  }\n\n  .layout-light {\n    --text: #0c0d10;\n    --text-muted: rgba(12, 13, 16, 0.62);\n  }\n\n  html.embed,\n  html.embed body {\n    width: 100%;\n    height: 100%;\n    min-height: 100%;\n  }\n\n  html.embed body {\n    background: transparent;\n    overflow-x: hidden;\n    overflow-y: auto;\n    -webkit-overflow-scrolling: touch;\n  }\n\n  html.embed .page {\n    width: 100%;\n    max-width: none;\n    min-height: 100%;\n    height: 100%;\n  }\n\n  html.embed .shell {\n    width: 100%;\n    max-width: none;\n    min-height: 100%;\n    height: 100%;\n  }\n\n  html.embed .content {\n    min-height: 100%;\n    display: flex;\n    flex-direction: column;\n  }\n\n  html.embed .layout-arc .arc-stage,\n  html.embed .layout-bubble .bubble-stage {\n    min-height: 100%;\n    height: 100%;\n  }\n\n  html.embed .layout-arc .shell {\n    min-height: 100%;\n    height: 100%;\n  }\n\n  html.embed [data-save-contact] {\n    display: none !important;\n  }\n";
